// newRestoreQueueWatchCmd implements `restore-queue watch`. Read-only polling
// loop: per tick, fetches /companies/{id}/restore-queues/ for every watched
// company, diffs against the prior tick, and prints either human lines or
// one NDJSON object per tick. Honors --dry-run, --once, Ctrl+C, --json.
func newRestoreQueueWatchCmd(flags *rootFlags) *cobra.Command {
	var interval time.Duration
	var companiesCSV string
	var once bool

	cmd := &cobra.Command{
		Use:         "watch",
		Short:       "Watch restore queues for one or more companies in real time",
		Annotations: map[string]string{"mcp:read-only": "true"},
		Long: `Watch tails every active company restore queue with periodic polling so
MSP techs can pin one terminal on every queue during a DR event instead of
tab-switching between portal pages.

Each tick, prints a diff against the previous tick:
  - which companies have new restore items (started)
  - which restore items completed
  - companies that errored

The first tick prints the full state. Subsequent ticks only print companies
whose queue changed; "no changes" prints if nothing moved.

Exits cleanly on Ctrl+C. Use --once for scripting (fetch once, exit 0).`,
		Example: `  # Watch every company with active queues, polling every 30s
  servosity-cli restore-queue watch

  # Watch a fixed set, polling every 10s
  servosity-cli restore-queue watch --companies 4421,5512 --interval 10s

  # Snapshot once and exit (good for cron / scripts)
  servosity-cli restore-queue watch --once --json`,
		RunE: func(cmd *cobra.Command, args []string) error {
			if dryRunOK(flags) {
				return nil
			}

			c, err := flags.newClient()
			if err != nil {
				return err
			}
			c.NoCache = true

			// Resolve target company set up-front; failures here are
			// usage-style, not transient-poll, so they should hard-fail.
			targets, err := resolveRestoreQueueTargets(cmd.Context(), c, flags, companiesCSV)
			if err != nil {
				return err
			}
			if len(targets) == 0 {
				note := "no companies to watch yet; pass --companies or run 'servosity-cli sync --resources companies' first"
				fmt.Fprintln(cmd.ErrOrStderr(), "hint: "+note)
				if !wantsHumanTable(cmd.OutOrStdout(), flags) {
					return printJSONFiltered(cmd.OutOrStdout(), map[string]any{"events": []any{}, "note": note}, flags)
				}
				fmt.Fprintln(cmd.OutOrStdout(), note)
				return nil
			}
			// Live-dogfood runs must never enter the watch loop: bound to a
			// single tick so the 30s matrix timeout cannot trip.
			if cliutil.IsDogfoodEnv() {
				once = true
			}

			// Adaptive limiter: with 50 companies and a 30s interval the
			// per-second budget is small, but a 5s interval × 50 companies
			// is 10 RPS sustained — pace ourselves so we never trigger 429.
			// Use 8 RPS as the floor; the limiter ramps up on success.
			if interval <= 0 {
				_ = cmd.Usage()
				return usageErr(fmt.Errorf("--interval must be > 0, got %s", interval))
			}
			limiter := cliutil.NewAdaptiveLimiter(8)

			ctx, stop := signal.NotifyContext(cmd.Context(), os.Interrupt)
			defer stop()

			prior := make(map[int64]*restoreQueueCompanyState, len(targets))
			ticker := time.NewTicker(interval)
			defer ticker.Stop()

			tick := 0
			runOne := func() error {
				tick++
				return runRestoreQueueTick(ctx, c, limiter, flags, targets, prior, tick, cmd.OutOrStdout())
			}

			if err := runOne(); err != nil {
				return err
			}
			if once {
				return nil
			}

			for {
				select {
				case <-ctx.Done():
					if !flags.asJSON {
						fmt.Fprintln(os.Stderr, "\nShutting down gracefully...")
					}
					return nil
				case <-ticker.C:
					if err := runOne(); err != nil {
						// Don't bail on a single tick failure — keep the
						// watch alive across transient errors. Loud to
						// stderr; JSON consumers see an "error" field.
						fmt.Fprintf(os.Stderr, "warning: tick %d failed: %v\n", tick, err)
					}
				}
			}
		},
	}

	cmd.Flags().DurationVar(&interval, "interval", 30*time.Second, "Polling interval")
	cmd.Flags().StringVar(&companiesCSV, "companies", "", "Comma-separated company IDs to watch (default: all companies in local store)")
	cmd.Flags().BoolVar(&once, "once", false, "Fetch once and exit (no loop)")

	return cmd
}

// restoreQueueTarget is one company we are watching.
type restoreQueueTarget struct {
	ID   int64
	Name string
}

// resolveRestoreQueueTargets resolves the watch set. Explicit --companies is
// authoritative; otherwise reads the local `companies` table. Live-fetching
// the company list every tick would balloon RPS on large fleets — sync
// already does that work.
func resolveRestoreQueueTargets(ctx context.Context, _ any, _ *rootFlags, csv string) ([]restoreQueueTarget, error) {
	if csv = strings.TrimSpace(csv); csv != "" {
		parts := strings.Split(csv, ",")
		out := make([]restoreQueueTarget, 0, len(parts))
		for _, p := range parts {
			p = strings.TrimSpace(p)
			if p == "" {
				continue
			}
			id, err := strconv.ParseInt(p, 10, 64)
			if err != nil {
				return nil, fmt.Errorf("invalid company id %q in --companies: %w", p, err)
			}
			out = append(out, restoreQueueTarget{ID: id, Name: ""})
		}
		return out, nil
	}

	db, err := store.OpenWithContext(ctx, defaultDBPath("servosity-cli"))
	if err != nil {
		return nil, fmt.Errorf("opening local store (run 'sync' first, or pass --companies): %w", err)
	}
	defer db.Close()

	// `companies` is its own table with a dedicated `name` column (see
	// store.go declarations); read it directly so we don't pay for a
	// json_extract scan on every restart.
	rows, err := db.DB().QueryContext(ctx, `SELECT CAST(id AS INTEGER), COALESCE(name,'') FROM companies ORDER BY id`)
	if err != nil {
		return nil, fmt.Errorf("listing companies from local store: %w", err)
	}
	defer rows.Close()

	var out []restoreQueueTarget
	for rows.Next() {
		var id int64
		var name string
		if err := rows.Scan(&id, &name); err != nil {
			continue
		}
		if id == 0 {
			continue
		}
		out = append(out, restoreQueueTarget{ID: id, Name: name})
	}
	return out, rows.Err()
}

// runRestoreQueueTick fetches every target's restore queue, diffs against
// `prior`, and emits one tick's worth of output. `prior` is mutated in place
// so the next call sees the new baseline.
func runRestoreQueueTick(
	ctx context.Context,
	c interface {
		Get(context.Context, string, map[string]string) (json.RawMessage, error)
	},
	limiter *cliutil.AdaptiveLimiter,
	flags *rootFlags,
	targets []restoreQueueTarget,
	prior map[int64]*restoreQueueCompanyState,
	tick int,
	stdout interface{ Write([]byte) (int, error) },
) error {
	now := time.Now().UTC()
	events := make([]restoreQueueTickEvent, 0, len(targets))
	changed := 0

	for _, t := range targets {
		select {
		case <-ctx.Done():
			return ctx.Err()
		default:
		}

		limiter.Wait()
		path := fmt.Sprintf("/companies/%d/restore-queues/", t.ID)
		data, err := c.Get(ctx, path, nil)
		if err != nil {
			limiter.OnRateLimit() // conservative — if it's not 429, ramp will recover
			fmt.Fprintf(os.Stderr, "warning: company %d fetch failed: %v\n", t.ID, err)
			continue
		}
		limiter.OnSuccess()

		ids, items := extractRestoreQueueIDs(data)
		_ = items

		state, seen := prior[t.ID]
		if !seen {
			state = &restoreQueueCompanyState{name: t.Name, ids: map[string]bool{}}
			prior[t.ID] = state
		}
		if state.name == "" {
			state.name = t.Name
		}

		completed := diffMissing(state.ids, ids)
		started := diffMissing(ids, state.ids)
		delta := len(ids) - len(state.ids)

		// Emit on: first sighting (tick==1), or any actual change.
		hasChange := tick == 1 || len(completed) > 0 || len(started) > 0 || delta != 0
		if hasChange {
			changed++
			events = append(events, restoreQueueTickEvent{
				ID:        t.ID,
				Name:      state.name,
				Active:    len(ids),
				Delta:     delta,
				Completed: completed,
				Started:   started,
			})
		}

		// Refresh prior state for next tick (do this AFTER diffing).
		state.ids = ids
	}

	if flags.asJSON {
		return emitRestoreQueueJSON(stdout, now, tick, events)
	}
	emitRestoreQueueHuman(stdout, now, events, changed)
	return nil
}

// extractRestoreQueueIDs pulls the set of active restore-queue item ids from
// a /companies/{id}/restore-queues/ response. The API may return either a
// bare array or a paginated `{results: [...]}` envelope; handle both.
func extractRestoreQueueIDs(data json.RawMessage) (map[string]bool, []map[string]any) {
	ids := map[string]bool{}
	if len(data) == 0 {
		return ids, nil
	}
	// Try bare array first.
	var arr []map[string]any
	if err := json.Unmarshal(data, &arr); err != nil {
		// Try {results: [...]}.
		var env struct {
			Results []map[string]any `json:"results"`
		}
		if err2 := json.Unmarshal(data, &env); err2 != nil {
			return ids, nil
		}
		arr = env.Results
	}
	for _, item := range arr {
		// Prefer "id"; fall back to "pk" or "uuid". Stringify so int ids
		// (4421) and uuid ids ("restore-789") share one key space.
		var idStr string
		if v, ok := item["id"]; ok && v != nil {
			idStr = fmt.Sprintf("%v", v)
		} else if v, ok := item["pk"]; ok && v != nil {
			idStr = fmt.Sprintf("%v", v)
		} else if v, ok := item["uuid"]; ok && v != nil {
			idStr = fmt.Sprintf("%v", v)
		}
		if idStr == "" {
			continue
		}
		ids[idStr] = true
	}
	return ids, arr
}

// diffMissing returns the sorted slice of keys in `a` that are not in `b`.
func diffMissing(a, b map[string]bool) []string {
	out := make([]string, 0)
	for k := range a {
		if !b[k] {
			out = append(out, k)
		}
	}
	sort.Strings(out)
	return out
}

// emitRestoreQueueHuman prints one human line per changed company plus a
// "no changes" line when the tick was a no-op.
func emitRestoreQueueHuman(w interface{ Write([]byte) (int, error) }, now time.Time, events []restoreQueueTickEvent, changed int) {
	stamp := now.Format("2006-01-02 15:04:05")
	if changed == 0 {
		fmt.Fprintf(w, "[%s] no changes\n", stamp)
		return
	}
	for _, e := range events {
		label := e.Name
		if label == "" {
			label = fmt.Sprintf("company %d", e.ID)
		} else {
			label = fmt.Sprintf("%s (%d)", label, e.ID)
		}
		parts := []string{fmt.Sprintf("[%s] %s: %d active restores", stamp, label, e.Active)}
		switch {
		case e.Delta > 0:
			parts = append(parts, fmt.Sprintf("(was %d, +%d)", e.Active-e.Delta, e.Delta))
		case e.Delta < 0:
			parts = append(parts, fmt.Sprintf("(was %d)", e.Active-e.Delta))
		}
		if len(e.Started) > 0 {
			parts = append(parts, fmt.Sprintf("started: %s", strings.Join(e.Started, ",")))
		}
		if len(e.Completed) > 0 {
			parts = append(parts, fmt.Sprintf("completed: %s", strings.Join(e.Completed, ",")))
		}
		fmt.Fprintln(w, strings.Join(parts, " — "))
	}
}

// emitRestoreQueueJSON writes one NDJSON object per tick to stdout. The
// envelope is deliberately flat (no provenance wrapper) so streamers can
// `jq -c` line-by-line without unwrapping.
func emitRestoreQueueJSON(w interface{ Write([]byte) (int, error) }, now time.Time, tick int, events []restoreQueueTickEvent) error {
	payload := map[string]any{
		"taken_at":  now.Format(time.RFC3339),
		"tick":      tick,
		"companies": events,
	}
	enc := json.NewEncoder(w)
	return enc.Encode(payload)
}
